   414→func (w *webhookAnnotator) addFailedOpenAnnotation() {
   415→	if w.attr == nil || w.attr.Attributes == nil {
   416→		return
   417→	}
   418→	value := w.webhook
   419→	if err := w.attr.Attributes.AddAnnotation(w.failedOpenAnnotationKey, value); err != nil {
