   424→func (w *webhookAnnotator) addMutationAnnotation(mutated bool) {
   425→	if w.attr == nil || w.attr.Attributes == nil {
   426→		return
   427→	}
   428→	value, err := mutationAnnotationValue(w.configuration, w.webhook, mutated)
